VALUES
  ('colonel-d0d1b9a2-moex-00018', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '丁公司於X5年11月1日取得A公司普通股20,000股，並分類為「透過 損益按公允價值衡量」之證券投資，成本$530,000，該項投資於 X5 年底 認列金融資產評價損失$30,000。丁公司於 X6 年 2 月 1 日出售 A 公司普 通股 5,000 股，當日每股市價為$36。A 公司於 X6 年 8 月 30 日宣告並發 放股票股利4%，X6年底普通股每股市價為$34。丁公司X6年度綜合損益 表中，因持有A公司股票所產生損益為：', '["$135,000", "$155,000", "$155,400", "$210,400 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00019', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '丙公司債券投資相關資料如下： 公允價值 成本 X5年底 X6年底 透過損益按公允價值衡量 $350,000 $340,000 $450,000 按攤銷後成本衡量 290,000 270,000 250,000 丙公司X6年綜合損益表內，金融資產評價利益為：', '["$60,000", "$90,000", "$100,000", "$110,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00020', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '乙公司X5年1月1日購入1台設備，該設備定價$105,000，付款條件3/10 ，n/30，乙公司X5年1月14日支付價款。該設備購入當天，乙公司亦支 付下列費用：運費$3,000、搬運途中不慎損壞之修理費用$2,200、安裝費 $1,950、試車費$1,200。該設備估計可用5年，殘值$3,000，使用年數合計 法提列折舊。X7 年1 月1 日，該設備進行重大修理支出$30,000，估計大 修後尚可再使用5年，無殘值。乙公司X7年度的折舊費用為：', '["$15,000", "$24,400", "$25,000", "$25,420"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00021', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '由於經營環境改變，乙公司認為生產電視機的設備價值可能發生減損。該 設備於X1年12月31日之相關資料為：成本$1,000,000，累計折舊（截至 X1 年12 月31 日）$520,000，淨公允價值$230,000，使用價值$240,000， 該設備預計尚可使用5年，無殘值，使用年數合計法提列折舊。該設備至 X2 年底仍未出售，淨公允價值$295,000，使用價值$315,000。乙公司 X2 年底該設備應認列的減損迴轉利益為：', '["$75,000", "$155,000", "$160,000", "$240,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00022', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司 X3 年 12 月 31 日調整前應收帳款餘額為$480,000，備抵壞帳貸餘 $24,000，應收帳款的帳齡分析如下： 帳 齡 金 額 可能收回機率 15天以內 $250,000 0.95 16～30天 80,000 0.92 31～45天 65,000 0.85 46～60天 33,000 0.78 61～90天 22,000 0.48 超過90天 ？ 0.00 甲公司採用帳齡分析法提列壞帳，X3年應提列壞帳費用之金額為：', '["$23,350", "$41,350", "$47,350", "$53,350 30650"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00023', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '丙公司的倉庫於X9年7月1日發生火災，除FOB起運點交貨之在途進貨 外，倉庫內剩餘存貨的估計殘值$9,500。該批在途進貨購價$58,000，運費 $1,500已經入帳。丙公司存貨相關資料如下：X9年1月1日存貨$62,500 ，X9年1月1日至7月1日間的進貨$403,500，進貨運費$2,500，進貨退 回及折讓$6,000。X9年1月1日至7月1日間的現金銷貨$222,000，賒銷 $250,000，銷貨退回$12,000，銷貨運費$4,500，平均毛利率為銷貨淨額之 25%。以毛利法計算丙公司火災的損失金額為：', '["$46,000", "$48,500", "$50,000", "$58,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00024', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '甲公司存貨使用定期盤存制度，X1年9月份的期初存貨共2,000單位，單 位成本$18，X1年9月份進貨與銷貨資料如下： 9月05日 進貨350單位，每單位成本$22 9月10日 銷貨450單位，每單位售價$38 9月13日 銷貨400單位，每單位售價$40 9月25日 進貨500單位，每單位成本$21 甲公司以成本與淨變現價值孰低法來評價存貨，每單位存貨於 X1 年 9 月 底的淨變現價值$20。在期末一次加權平均法下，甲公司X1年9月底之存 貨金額為：', '["$38,040", "$40,000", "$40,667", "$42,820"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00025', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '舒結公司 X3 年 1 月 1 日備抵損失貸方餘額$95,200，X3 年舒結公司沖銷 了$68,544 的應收帳款，同時也收回了原先已打消壞帳的應收帳款$19,992 ，X3年的預期信用減損損失為$67,592，X3年12月31日公司合理估計應 收帳款餘額的 6%可能無法收回。舒結公司 X3 年 12 月 31 日應收帳款的 餘額為：', '["$1,186,300", "$1,126,533", "$1,570,800", "$1,904,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00026', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '北平公司於X1 年12月31 日買入南山公司3 年期公司債，面額$500,000 ，票面利率 3%，每年 12 月 31 日付息 1 次。當日該公司債的公允價值為 $498,000，12 個月預期信用損失估計金額為$5,000，北平公司另外支付交 易成本$8,000。若北平公司將該公司債做為按攤銷後成本衡量之投資，則 其X1年12月31日之總帳面金額及攤銷後成本分別為：', '["$506,000、$501,000", "$500,000、$508,000", "$498,000、$506,000", "$498,000、$501,000 30650"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL),
  ('colonel-d0d1b9a2-moex-00027', 'colonel-d0d1b9a2', 'colonel-d0d1b9a2-moex-113-e0b1f2ed', 'sub-colonel-d0d1b9a2-01', NULL, 'single_choice', '陽光科技公司於 X6 年 1 月 1 日購買 1 項專利權，支付$200,000 作為購買 價格。此外，該公司還支付$25,000 的律師費用以完成購買過程，並支出 $10,000 用於專利權的初步市場研究。該專利權的預計使用壽命為 10 年。 依據國際會計準則第38號「無形資產」，陽光科技公司專利權的成本為：', '["$200,000", "$225,000", "$235,000", "$245,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:56+00:00", "source_pdf_sha1": "96d5295faf56", "answer_pdf_sha1": "2f6eb3654efb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "306", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "會計"}'::jsonb, NULL)
